    if (S == T) {
        cout &lt;&lt; 0 &lt;&lt; "\n";
        return 0;
    }

    // Initialize distances for both searches.
    vector&lt;int&gt; distS(N + 1, -1), distT(N + 1, -1);
    queue&lt;int&gt; qs, qt;

