        if (qs.size() &lt;= qt.size()) {
            int size = qs.size();
            for (int i = 0; i &lt; size; i++) {
                int u = qs.front();
                qs.pop();
                for (int v : graph[u]) {
                    if (distS[v] == -1) {
                        distS[v] = distS[u] + 1;
                        qs.push(v);
                        if (distT[v] != -1) {
                            answer = distS[v] + distT[v];
                            found = true;
